I'm working on a problem where I need to find the maximum XOR value of a number X with any element in a specific range [L, R] of an array that is being updated dynamically. I've implemented a Binary Trie to handle this, but I'm running into a Segmentation Fault on some test cases. I suspect it's related to how I'm tracking the indices of the elements within the Trie nodes. Here is my current code:

#include <iostream>
#include <vector>
using namespace std;

struct Node {
    Node *child[2];
    int max_idx;
    Node() { child[0] = child[1] = nullptr; max_idx = -1; }
};

class PersistentTrie {
    Node* root;
public:
    PersistentTrie() { root = new Node(); }

    void insert(int val, int idx) {
        Node* curr = root;
        for(int i=30; i>=0; i--) {
            int bit = (val >> i) & 1;
            if(!curr->child[bit]) curr->child[bit] = new Node();
            curr = curr->child[bit];
            curr->max_idx = idx;
        }
    }

    int query(int X, int L, int R) {
        Node* curr = root;
        int res = 0;
        for(int i=30; i>=0; i--) {
            int bit = (X >> i) & 1;
            if(curr->child[1-bit] && curr->child[1-bit]->max_idx >= L) {
                res |= (1 << i);
                curr = curr->child[1-bit];
            } else if(curr->child[bit] && curr->child[bit]->max_idx >= L) {
                curr = curr->child[bit];
            } else {
                return -1; // Should not happen
            }
        }
        return res;
    }
};

int main() {
    int Q;
    cin >> Q;
    PersistentTrie pt;
    int count = 0;
    while(Q--) {
        int type;
        cin >> type;
        if(type == 0) {
            int x; cin >> x;
            pt.insert(x, count++);
        } else {
            int l, r, x;
            cin >> l >> r >> x;
            cout << pt.query(x, l, r) << endl;
        }
    }
    return 0;
}

